import React from "react";

function SingleRecordQuestion({
  fields,
  value,
  onChange
}) {

  const data = value || {};

  const handleChange = (
    key,
    val
  ) => {

    onChange({
      ...data,
      [key]: val
    });

  };

  return (

    <div>

      {

        fields.map(
          (field) => (

            <div
              key={field.key}
              style={{
                marginBottom:"20px"
              }}
            >

              <label
                style={{
                  display:"block",
                  fontWeight:"600",
                  marginBottom:"8px"
                }}
              >
                {
                  field.label ||
                  field.key
                }
              </label>

              {

                field.type === "textarea" ? (

                  <textarea
                    rows="4"
                    value={
                      data[field.key] || ""
                    }
                    onChange={(e)=>
                      handleChange(
                        field.key,
                        e.target.value
                      )
                    }
                    style={{
                      width:"100%",
                      padding:"10px"
                    }}
                  />

                ) :

                field.type === "file" ? (

                  <input
                    type="file"
                    onChange={(e)=>
                      handleChange(
                        field.key,
                        e.target.files[0]
                      )
                    }
                  />

                ) :

                (

                  <input
                    type="text"
                    value={
                      data[field.key] || ""
                    }
                    onChange={(e)=>
                      handleChange(
                        field.key,
                        e.target.value
                      )
                    }
                    style={{
                      width:"100%",
                      padding:"10px"
                    }}
                  />

                )

              }

            </div>

          )
        )

      }

    </div>

  );

}

export default SingleRecordQuestion;
